// Linear transition: Transition to incoming value (e.g. velocity of button press) within a certain amount of time.

// Parameters

transition_time_in_ms = 1500;

// Code

y = abs(x - y) > 0.05 ? (
    x * min(rel_time / transition_time_in_ms, 1)
) : (
    stop
);

